import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import { Link } from 'react-router-dom';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

// Fix react-leaflet default icon loading issue
let DefaultIcon = L.icon({
    iconUrl: icon,
    shadowUrl: iconShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41],
    popupAnchor: [1, -34]
});
L.Marker.prototype.options.icon = DefaultIcon;

// Map controller to automatically pan/zoom map on data change
function MapController({ center, zoom }) {
  const map = useMap();
  useEffect(() => {
     if (center) {
         map.flyTo(center, zoom, {
             animate: true,
             duration: 1.5
         });
     }
  }, [center, zoom, map]);
  return null;
}

export default function ParkingMap() {
    const [parkingLots, setParkingLots] = useState([]);
    const [districts, setDistricts] = useState([]);
    const [selectedDistrict, setSelectedDistrict] = useState("");

    // Tamil Nadu default center
    const defaultCenter = [11.1271, 78.6569];
    const defaultZoom = 7;

    const [mapCenter, setMapCenter] = useState(defaultCenter);
    const [mapZoom, setMapZoom] = useState(defaultZoom);

    useEffect(() => {
        // Fetch all parking lots
        axios.get("http://localhost:5000/parking")
             .then(res => {
                 setParkingLots(res.data);

                 // Extract valid unique districts dynamically
                 const uniqueDistricts = [...new Set(res.data.map(lot => lot.district).filter(Boolean))];
                 setDistricts(uniqueDistricts);
             })
             .catch(err => console.error("Error fetching parking lots:", err));
    }, []);

    const handleDistrictChange = (e) => {
        const district = e.target.value;
        setSelectedDistrict(district);

        if (!district) {
            // Reset to Tamil Nadu
            setMapCenter(defaultCenter);
            setMapZoom(defaultZoom);
            return;
        }

        // Calculate center based on available parking lots in the district
        const districtLots = parkingLots.filter(l => l.district === district && l.lat && l.lng);

        if (districtLots.length > 0) {
            const avgLat = districtLots.reduce((sum, l) => sum + l.lat, 0) / districtLots.length;
            const avgLng = districtLots.reduce((sum, l) => sum + l.lng, 0) / districtLots.length;

            setMapCenter([avgLat, avgLng]);
            setMapZoom(12); // zoom in nicely into district
        }
    };

    // Filter lots
    const visibleLots = selectedDistrict 
        ? parkingLots.filter(l => l.district === selectedDistrict)
        : parkingLots;

    return (
        <div className="dashboard-container" style={{ display: 'flex', flexDirection: 'column', height: 'calc(100vh - 100px)' }}>
            <div className="dashboard-header" style={{ marginBottom: '20px' }}>
                <div>
                    <h1 className="dashboard-title">Parking Map</h1>
                    <p className="dashboard-subtitle">Explore parking lots visually across Tamil Nadu</p>
                </div>
            </div>

            <div className="card" style={{ flex: 1, display: 'flex', flexDirection: 'column', padding: '20px' }}>
                <div style={{ marginBottom: '20px', display: 'flex', gap: '15px', alignItems: 'center' }}>
                    <label style={{ fontWeight: '600', color: 'var(--text-primary)' }}>Find your district:</label>
                    <select 
                        className="form-input" 
                        style={{ maxWidth: '300px' }}
                        value={selectedDistrict}
                        onChange={handleDistrictChange}
                    >
                        <option value="">All Tamil Nadu</option>
                        {districts.map(d => (
                            <option key={d} value={d}>{d}</option>
                        ))}
                    </select>
                </div>

                <div style={{ flex: 1, borderRadius: '12px', overflow: 'hidden', border: '1px solid var(--border-color)', position: 'relative' }}>
                    <MapContainer center={defaultCenter} zoom={defaultZoom} style={{ height: '100%', width: '100%', zIndex: 0 }}>
                        <TileLayer
                            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                        />
                        <MapController center={mapCenter} zoom={mapZoom} />

                        {visibleLots.map(lot => (
                            lot.lat && lot.lng && (
                                <Marker key={lot._id} position={[lot.lat, lot.lng]}>
                                    <Popup>
                                        <div style={{ padding: '5px', textAlign: 'center' }}>
                                            <h3 style={{ fontSize: '16px', fontWeight: 'bold', marginBottom: '5px', color: 'var(--text-primary)' }}>{lot.name}</h3>
                                            <p style={{ fontSize: '13px', color: 'var(--text-secondary)', marginBottom: '10px' }}>{lot.location}</p>
                                            <p style={{ fontSize: '12px', background: 'var(--bg-secondary)', padding: '4px 8px', borderRadius: '4px', display: 'inline-block', marginBottom: '15px' }}>
                                                {lot.district}
                                            </p>
                                            <br/>
                                            <Link 
                                                to={`/slots/${lot._id}`} 
                                                className="primary-btn" 
                                                style={{ display: 'inline-block', textDecoration: 'none', padding: '8px 16px', fontSize: '13px' }}
                                            >
                                                Book Spot
                                            </Link>
                                        </div>
                                    </Popup>
                                </Marker>
                            )
                        ))}
                    </MapContainer>
                </div>
            </div>
        </div>
    );
}
